export function initialize(sentinel, dotNetHelper) {
    const observer = new IntersectionObserver(entries => {
        if (entries[0].isIntersecting) {
            dotNetHelper.invokeMethodAsync('OnSentinelVisible');
        }
    }, { rootMargin: '200px' });

    observer.observe(sentinel);

    return observer;
}

export function dispose(observer, sentinel) {
    observer.unobserve(sentinel);
    observer.disconnect();
}

@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="infinite-scroll-sentinel">
            @if (isLoading)
            {
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    private ElementReference sentinelRef;
    private IJSObjectReference? module;
    private IJSObjectReference? observer;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotNetRef;
    private bool isLoading;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && HasMore)
        {
            await InitializeObserver();
        }
    }

    private async Task InitializeObserver()
    {
        module = await JS.InvokeAsync<IJSObjectReference>(
            "import", "./_content/sv-72797f5f14264177b2acca9081778380/Components/InfiniteScrollList.razor.js");

        // Fallback for same-project colocation path
        module ??= await JS.InvokeAsync<IJSObjectReference>(
            "import", "./Components/InfiniteScrollList.razor.js");

        dotNetRef = DotNetObjectReference.Create(this);
        observer = await module.InvokeAsync<IJSObjectReference>("initialize", sentinelRef, dotNetRef);
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore)
            return;

        isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (module is not null && observer is not null)
        {
            await module.InvokeVoidAsync("dispose", observer, sentinelRef);
            await module.DisposeAsync();
        }

        dotNetRef?.Dispose();
    }
}

.infinite-scroll-container {
    overflow-y: auto;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem;
}

